import{_ as t,o,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Login & Account Problems","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/login.md","filePath":"troubleshooting/login.md"}'),r={name:"troubleshooting/login.md"};function s(n,e,l,d,c,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="login-account-problems" tabindex="-1">Login &amp; Account Problems <a class="header-anchor" href="#login-account-problems" aria-label="Permalink to &quot;Login &amp; Account Problems&quot;">​</a></h1><p>Use the short path that matches what is stopping you from getting in.</p><h2 id="_1-wrong-password-too-many-times" tabindex="-1">1. Wrong password too many times <a class="header-anchor" href="#_1-wrong-password-too-many-times" aria-label="Permalink to &quot;1. Wrong password too many times&quot;">​</a></h2><ol><li>Stop retrying.</li><li>Wait for the cooldown to pass. The login system is rate-limited, and repeated failures only make it worse.</li><li>If you still do not know the password, use <a href="./../getting-started/forgot-password.html">Reset a Forgotten Password</a>.</li></ol><h2 id="_2-i-forgot-my-password" tabindex="-1">2. I forgot my password <a class="header-anchor" href="#_2-i-forgot-my-password" aria-label="Permalink to &quot;2. I forgot my password&quot;">​</a></h2><ol><li>Open <a href="./../getting-started/forgot-password.html">Reset a Forgotten Password</a>.</li><li>Submit the reset request.</li><li>Contact your King or Supreme Admin if the reset is urgent.</li></ol><h2 id="_3-my-account-is-still-pending" tabindex="-1">3. My account is still pending <a class="header-anchor" href="#_3-my-account-is-still-pending" aria-label="Permalink to &quot;3. My account is still pending&quot;">​</a></h2><ol><li>Re-read <a href="./../getting-started/registering.html">Request an Account</a>.</li><li>Wait for a senior role to review the request.</li><li>If it has been pending for too long, contact your Alliance Leader, King, or Supreme Admin.</li></ol><h2 id="_4-my-request-was-rejected-or-needs-more-information" tabindex="-1">4. My request was rejected or needs more information <a class="header-anchor" href="#_4-my-request-was-rejected-or-needs-more-information" aria-label="Permalink to &quot;4. My request was rejected or needs more information&quot;">​</a></h2><ol><li>Review <a href="./../getting-started/registering.html">Request an Account</a>.</li><li>If more information is needed, provide it through the process your admins use.</li><li>If it was rejected and you think that is wrong, contact the approving admin directly.</li></ol><h2 id="_5-my-account-exists-but-still-cannot-get-in" tabindex="-1">5. My account exists but still cannot get in <a class="header-anchor" href="#_5-my-account-exists-but-still-cannot-get-in" aria-label="Permalink to &quot;5. My account exists but still cannot get in&quot;">​</a></h2><ol><li>Make sure you are using the correct username.</li><li>Check whether the issue is really access after login instead of login itself. If so, read <a href="./../getting-started/access-denied.html">&quot;You don&#39;t have access&quot;</a>.</li><li>Ask an admin to review the account in the user-management flow. The relevant admin guide starts at <a href="./../how-to/create-user.html">Create a User</a> and <a href="./../how-to/edit-user.html">Edit a User &amp; Reset Their Password</a>.</li></ol>',12)])])}const g=t(r,[["render",s]]);export{u as __pageData,g as default};
